import React, { useRef } from 'react';
import { motion, useInView } from 'framer-motion';
import { HiAcademicCap } from 'react-icons/hi';
import { education } from '../data/portfolioData';

export default function Education() {
  const ref = useRef(null);
  const isInView = useInView(ref, { once: true, margin: '-80px' });
  const edu = education[0];

  return (
    <section id="education" className="py-28 px-6 bg-[#080810]">
      <div className="max-w-3xl mx-auto">
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={isInView ? { opacity: 1, y: 0 } : {}}
          transition={{ duration: 0.6 }}
          className="text-center mb-16"
        >
          <span className="font-mono text-[#6c63ff] text-sm tracking-widest uppercase">// academic</span>
          <h2 className="font-space text-4xl md:text-5xl font-bold text-white mt-3 mb-4">
            Education
          </h2>
        </motion.div>

        <motion.div
          ref={ref}
          initial={{ opacity: 0, y: 30 }}
          animate={isInView ? { opacity: 1, y: 0 } : {}}
          transition={{ duration: 0.7, delay: 0.1 }}
          className="relative rounded-2xl border border-[#6c63ff]/20 overflow-hidden"
          style={{ background: 'linear-gradient(135deg, #0f0f1c 0%, #0a0a12 100%)' }}
        >
          {/* Top highlight */}
          <div className="absolute top-0 left-1/2 -translate-x-1/2 w-1/2 h-px bg-gradient-to-r from-transparent via-[#6c63ff]/50 to-transparent" />
          <div className="absolute -top-20 right-0 w-64 h-64 bg-[#6c63ff]/5 rounded-full blur-3xl pointer-events-none" />

          <div className="relative p-8 md:p-10">
            <div className="flex flex-col sm:flex-row items-start gap-6 mb-8">
              <div className="p-4 rounded-2xl bg-[#6c63ff]/10 border border-[#6c63ff]/20 shrink-0">
                <HiAcademicCap size={32} className="text-[#6c63ff]" />
              </div>
              <div className="flex-1">
                <h3 className="font-space text-xl font-bold text-white mb-1.5">{edu.degree}</h3>
                <p className="text-[#38bdf8] font-medium mb-1">{edu.institution}</p>
                <p className="text-slate-500 text-sm font-mono">{edu.period}</p>
              </div>
              <div className="sm:text-right shrink-0">
                <div className="font-space text-4xl font-bold bg-gradient-to-br from-[#6c63ff] to-[#38bdf8] bg-clip-text text-transparent">
                  {edu.cgpa}
                </div>
                <p className="text-slate-500 text-xs mt-1 font-mono uppercase tracking-wider">CGPA</p>
              </div>
            </div>

            <div>
              <p className="font-mono text-xs uppercase tracking-widest text-slate-500 mb-4">
                Relevant Coursework
              </p>
              <div className="flex flex-wrap gap-2.5">
                {edu.courses.map((course) => (
                  <span
                    key={course}
                    className="px-3.5 py-1.5 rounded-xl text-sm border border-white/[0.06] bg-white/[0.03] text-slate-300 hover:border-[#6c63ff]/30 hover:text-white transition-colors duration-200 cursor-default"
                  >
                    {course}
                  </span>
                ))}
              </div>
            </div>
          </div>
        </motion.div>
      </div>
    </section>
  );
}
